import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';

import { useAuth } from '../../context/AuthContext';
import { loginSchema } from '../../utils/validationSchemas';
import AuthLayout from '../../components/auth/AuthLayout';

const LoginPage = () => {
  const navigate  = useNavigate();
  const location  = useLocation();
  const { login } = useAuth();

  const [serverError,     setServerError]     = useState('');
  const [infoMsg,         setInfoMsg]         = useState(location.state?.message || '');
  const [isSubmitting,    setIsSubmitting]    = useState(false);
  const [unverifiedEmail, setUnverifiedEmail] = useState('');

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm({ resolver: zodResolver(loginSchema) });

  const onSubmit = async (data) => {
    setServerError('');
    setInfoMsg('');
    setUnverifiedEmail('');
    setIsSubmitting(true);

    const result = await login(data);
    setIsSubmitting(false);

    if (result.success) {
      const from = location.state?.from?.pathname;
      const roleDashboards = {
        customer: '/dashboard',
        provider: '/provider/dashboard',
        admin:    '/admin/dashboard',
      };
      navigate(from || roleDashboards[result.user.role] || '/dashboard', { replace: true });
    } else {
      if (result.code === 'EMAIL_NOT_VERIFIED') {
        setUnverifiedEmail(result.data?.email || '');
      }
      setServerError(result.message || 'Login failed.');
    }
  };

  return (
    <AuthLayout
      title="Welcome back"
      subtitle="Sign in to manage your property services."
    >
      <form onSubmit={handleSubmit(onSubmit)} noValidate>

        {/* Info message */}
        {infoMsg && !serverError && (
          <div className="auth-info-box">
            ℹ️ {infoMsg}
          </div>
        )}

        {/* Email */}
        <div style={{ marginBottom: '16px' }}>
          <label className="auth-form-label">
            Email Address <span style={{ color: '#e74c3c' }}>*</span>
          </label>
          <input
            type="email"
            className="auth-form-input"
            placeholder="you@example.com"
            autoComplete="email"
            aria-invalid={!!errors.email}
            {...register('email')}
          />
          {errors.email && <p className="auth-form-error">⚠ {errors.email.message}</p>}
        </div>

        {/* Password */}
        <div style={{ marginBottom: '6px' }}>
          <label className="auth-form-label">
            Password <span style={{ color: '#e74c3c' }}>*</span>
          </label>
          <input
            type="password"
            className="auth-form-input"
            placeholder="Your password"
            autoComplete="current-password"
            aria-invalid={!!errors.password}
            {...register('password')}
          />
          {errors.password && <p className="auth-form-error">⚠ {errors.password.message}</p>}
        </div>

        {/* Forgot password */}
        <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '20px', marginTop: '8px' }}>
          <Link to="/auth/forgot-password" className="auth-link" style={{ fontSize: '13px' }}>
            Forgot password?
          </Link>
        </div>

        {/* Server error */}
        {serverError && (
          <div role="alert" className="auth-error-box">
            {serverError}
            {unverifiedEmail && (
              <div style={{ marginTop: '8px', fontSize: '12px' }}>
                Haven't verified yet?{' '}
                <Link
                  to="/auth/resend-verification"
                  state={{ email: unverifiedEmail }}
                  className="auth-link"
                  style={{ fontSize: '12px' }}
                >
                  Resend verification email →
                </Link>
              </div>
            )}
          </div>
        )}

        {/* Submit */}
        <button
          type="submit"
          disabled={isSubmitting}
          className="auth-submit-btn"
        >
          {isSubmitting ? 'Signing in…' : 'Sign In'}
        </button>

        {/* Divider */}
        <div className="auth-divider">
          <span className="auth-divider-line" />
          <span className="auth-divider-text">New to PropMaintain?</span>
          <span className="auth-divider-line" />
        </div>

        {/* Register link */}
        <Link to="/auth/register" className="auth-secondary-btn">
          Create an Account
        </Link>

      </form>
    </AuthLayout>
  );
};

export default LoginPage;
